#ifndef KERNEL_H
#define KERNEL_H

#include <cuda_fp16.h>
#include <cuda_runtime.h>
#include <stdint.h>

// Constants for fixed dimensions
constexpr int FIXED_N = 4096;
constexpr int FIXED_K = 14336;

// Tile dimensions for shared memory (optimized for A800 tensor cores)
constexpr int TILE_M = 32;
constexpr int TILE_N = 32;
constexpr int TILE_K = 32;

// Thread block configuration
constexpr int THREADS_PER_BLOCK = 1024;  // 32x32 threads per block

// Kernel declaration
__global__ void gemm_kernel(
    const __half* __restrict__ A,
    const __half* __restrict__ B,
    __half* __restrict__ C,
    int M,
    int N,
    int K
);

// Host function declaration
void launch_gemm(
    const __half* A,
    const __half* B,
    __half* C,
    int M,
    int N,
    int K
);

#endif // KERNEL_H

#include "kernel.h"
#include <cuda_fp16.h>
#include <cstdio>

// Shared memory tiles for A and B with padding to avoid bank conflicts
__shared__ __half shared_A[TILE_M][TILE_K + 1];  // +1 padding for bank conflict avoidance
__shared__ __half shared_B[TILE_N][TILE_K + 1];  // +1 padding for bank conflict avoidance

// GEMM kernel optimized for A800
// Computes C = A @ B.T where:
// - A: [M, K]
// - B: [N, K]
// - C: [M, N]
// C[i, j] = sum_k(A[i, k] * B[j, k])
__global__ void gemm_kernel(
    const __half* __restrict__ A,
    const __half* __restrict__ B,
    __half* __restrict__ C,
    int M,
    int N,
    int K
) {
    // Calculate global thread indices
    int row = blockIdx.y * TILE_M + threadIdx.y;
    int col = blockIdx.x * TILE_N + threadIdx.x;

    // Accumulator in registers (FP32 for precision)
    float acc = 0.0f;

    // Iterate through K dimension in tiles
    for (int k = 0; k < K; k += TILE_K) {
        // Load A tile into shared memory
        // Thread (threadIdx.x, threadIdx.y) loads A[block_row_start + threadIdx.y, k + threadIdx.x]
        // threadIdx.y: row index within tile (0 to TILE_M-1)
        // threadIdx.x: K index within tile (0 to TILE_K-1)
        int a_row = blockIdx.y * TILE_M + threadIdx.y;
        int a_col = k + threadIdx.x;

        if (threadIdx.y < TILE_M && threadIdx.x < TILE_K) {
            if (a_row < M && a_col < K) {
                shared_A[threadIdx.y][threadIdx.x] = A[a_row * K + a_col];
            } else {
                shared_A[threadIdx.y][threadIdx.x] = __float2half(0.0f);
            }
        }

        // Load B tile into shared memory
        // Thread (threadIdx.x, threadIdx.y) loads B[block_col_start + threadIdx.x, k + threadIdx.y]
        // threadIdx.x: N index within tile (0 to TILE_N-1)
        // threadIdx.y: K index within tile (0 to TILE_K-1)
        int b_row = blockIdx.x * TILE_N + threadIdx.x;
        int b_col = k + threadIdx.y;

        if (threadIdx.x < TILE_N && threadIdx.y < TILE_K) {
            if (b_row < N && b_col < K) {
                shared_B[threadIdx.x][threadIdx.y] = B[b_row * K + b_col];
            } else {
                shared_B[threadIdx.x][threadIdx.y] = __float2half(0.0f);
            }
        }

        __syncthreads();

        // Perform matrix multiplication for this tile
        // Thread (threadIdx.x, threadIdx.y) computes:
        // C[row, col] += A[row, k+i] * B[col, k+i]
        // shared_A[threadIdx.y][i] = A[row, k+i]
        // shared_B[threadIdx.x][i] = B[col, k+i]
        #pragma unroll
        for (int i = 0; i < TILE_K; i++) {
            acc += __half2float(shared_A[threadIdx.y][i]) * __half2float(shared_B[threadIdx.x][i]);
        }

        __syncthreads();
    }

    // Write result to output matrix if within bounds
    if (row < M && col < N) {
        C[row * N + col] = __float2half(acc);
    }
}

// Host function to launch the kernel
void launch_gemm(
    const __half* A,
    const __half* B,
    __half* C,
    int M,
    int N,
    int K
) {
    // Define block and grid dimensions
    dim3 blockDim(TILE_N, TILE_M);  // 32x32 = 1024 threads per block
    dim3 gridDim((N + TILE_N - 1) / TILE_N, (M + TILE_M - 1) / TILE_M);

    // Launch kernel
    gemm_kernel<<<gridDim, blockDim>>>(A, B, C, M, N, K);

    // Check for kernel launch errors
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        fprintf(stderr, "CUDA kernel launch error: %s\n", cudaGetErrorString(err));
    }
}

#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include "kernel.h"
#include <stdexcept>
#include <string>

// Helper function to check CUDA errors
void check_cuda_error(cudaError_t err, const std::string& context) {
    if (err != cudaSuccess) {
        throw std::runtime_error(std::string("CUDA error in ") + context + ": " + cudaGetErrorString(err));
    }
}

// Helper function to validate tensor properties
void validate_tensor(const torch::Tensor& tensor, const std::string& name, int expected_dim) {
    if (!tensor.is_cuda()) {
        throw std::runtime_error(name + " must be on CUDA device");
    }
    if (tensor.dtype() != torch::kHalf) {
        throw std::runtime_error(name + " must be of type float16 (torch.float16)");
    }
    if (tensor.dim() != expected_dim) {
        throw std::runtime_error(name + " must have " + std::to_string(expected_dim) + " dimensions");
    }
    if (!tensor.is_contiguous()) {
        throw std::runtime_error(name + " must be contiguous in memory");
    }
}

// Main run function that takes torch tensors (A, B, C)
// C is passed as output tensor to be filled in-place
torch::Tensor run(const torch::Tensor& A, const torch::Tensor& B, torch::Tensor& C) {
    // Validate input tensors
    validate_tensor(A, "Input A", 2);
    validate_tensor(B, "Input B", 2);
    validate_tensor(C, "Output C", 2);

    // Extract dimensions
    int64_t M = A.size(0);
    int64_t K_A = A.size(1);
    int64_t N_B = B.size(0);
    int64_t K_B = B.size(1);

    // Validate dimensions match specification
    if (K_A != FIXED_K) {
        throw std::runtime_error("A's K dimension must be " + std::to_string(FIXED_K) + ", got " + std::to_string(K_A));
    }
    if (N_B != FIXED_N) {
        throw std::runtime_error("B's N dimension must be " + std::to_string(FIXED_N) + ", got " + std::to_string(N_B));
    }
    if (K_B != FIXED_K) {
        throw std::runtime_error("B's K dimension must be " + std::to_string(FIXED_K) + ", got " + std::to_string(K_B));
    }

    // Validate output tensor shape
    if (C.size(0) != M || C.size(1) != FIXED_N) {
        throw std::runtime_error("Output C must have shape [" + std::to_string(M) + ", " + std::to_string(FIXED_N) + "]");
    }

    // Get raw pointers using __half type
    const __half* A_ptr = static_cast<const __half*>(A.data_ptr());
    const __half* B_ptr = static_cast<const __half*>(B.data_ptr());
    __half* C_ptr = static_cast<__half*>(C.data_ptr());

    // Launch kernel
    launch_gemm(A_ptr, B_ptr, C_ptr, (int)M, (int)FIXED_N, (int)FIXED_K);

    // Synchronize and check for errors
    check_cuda_error(cudaDeviceSynchronize(), "GEMM kernel execution");
    check_cuda_error(cudaGetLastError(), "GEMM kernel completion");

    return C;
}

// Pybind11 module definition
PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.doc() = "CUDA GEMM kernel optimized for A800 GPU";
    m.def("run", &run, "Execute GEMM operation: C = A @ B.T");
}
